function TestimonialCard({ name, initial, review, companyInitial, companyName, reply }) {
  return (
    <div className="bg-white rounded-xl shadow-md overflow-hidden h-full p-5 md:p-6 flex flex-col">
      <div className="flex items-center gap-3">
        <div className="w-12 h-12 rounded-full bg-gradient-to-br from-pink-400 to-orange-300 flex items-center justify-center text-white font-semibold text-base">
          {initial}
        </div>
        <div className="flex flex-col">
          <div className="font-bold text-gray-900 text-base md:text-lg">{name}</div>
          <div className="flex items-center text-yellow-400 text-sm" aria-label="5 star rating">
            {Array.from({ length: 5 }).map((_, i) => (
              <span key={i}>⭐</span>
            ))}
          </div>
        </div>
      </div>
      <div className="relative mt-4 rounded-lg p-4 leading-relaxed text-sm md:text-base bg-gray-100 text-gray-700">
        <p className="m-0">{review}</p>
        <span aria-hidden="true" className="absolute left-4 -bottom-2 w-3 h-3 rotate-45 bg-gray-100"></span>
      </div>
      <div className="my-4 border-t border-gray-200" aria-hidden="true"></div>
      <div className="relative rounded-xl p-4 text-white bg-gradient-to-br from-blue-500 to-purple-600 shadow-md">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-md bg-white/20 flex items-center justify-center font-extrabold">
            {companyInitial}
          </div>
          <div className="font-bold text-base md:text-lg">{companyName}</div>
        </div>
        <div className="mt-3 px-4 py-3 rounded-lg bg-white/20">
          <p className="m-0 text-gray-100">{reply}</p>
        </div>
        <span aria-hidden="true" className="absolute left-4 -top-2 w-3 h-3 rotate-45 bg-blue-500"></span>
      </div>
    </div>
  );
}

export default function Testimonials() {
  const firstRow = testimonials.slice(0, 2);
  const remaining = testimonials.slice(2);

  return (
    <section className="w-full min-h-screen bg-black px-4 py-10">
      <div className="max-w-6xl mx-auto">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {firstRow.map((t, idx) => (
            <TestimonialCard
              key={`first-${idx}`}
              name={t.name}
              initial={t.initial}
              review={t.review}
              companyInitial={t.companyInitial}
              companyName={t.companyName}
              reply={t.reply}
            />
          ))}
        </div>
        <div className="mt-8 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-2 gap-6">
          {remaining.map((t, idx) => (
            <TestimonialCard
              key={`remaining-${idx}`}
              name={t.name}
              initial={t.initial}
              review={t.review}
              companyInitial={t.companyInitial}
              companyName={t.companyName}
              reply={t.reply}
            />
          ))}
        </div>
      </div>
    </section>
  );
}
